function parseCsvLine(line) {
  const fields = [];
  let i = 0;

  while (i <= line.length) {
    if (line[i] === '"') {
      // Quoted field: consume until closing quote, handling "" escapes
      let field = '';
      i++; // skip opening quote
      while (i < line.length) {
        if (line[i] === '"') {
          if (line[i + 1] === '"') {
            field += '"';
            i += 2;
          } else {
            i++; // skip closing quote
            break;
          }
        } else {
          field += line[i];
          i++;
        }
      }
      fields.push(field);
      // skip comma separator
      if (line[i] === ',') i++;
    } else {
      // Unquoted field: read until next comma or end
      const start = i;
      while (i < line.length && line[i] !== ',') i++;
      fields.push(line.slice(start, i));
      // skip comma separator
      if (line[i] === ',') i++;
      else break; // end of line — stop after pushing the final field
    }
  }

  return fields;
}

